"use client";

import { FormEvent, useEffect, useState } from "react";
import Link from "next/link";
import { CalendarDays, CircleDollarSign, Clock3, Crown, Eye, ImagePlus, Megaphone, Package, Plus, Sparkles, UserPlus, UsersRound } from "lucide-react";
import { getSessionForScope, salonSupabase as supabase } from "@/lib/supabase";
import { subscribeToOwnerUpdates } from "@/lib/ownerRealtime";
import BaseImageUpload from "@/components/ImageUpload";
import SafeImage from "@/components/site/SafeImage";
import OwnerDashboardShell, { DashboardSection } from "@/components/owner/OwnerDashboardShell";
import { hasPlanFeature, isSubscriptionActive, normalizePlan, PLAN_ORDER, SUBSCRIPTION_PLANS, type SubscriptionPlan } from "@/lib/plans";
import { EMAIL_PATTERN, isValidEmail, isValidUsPhone, normalizeEmail, normalizeUsPhone, US_PHONE_PATTERN } from "@/lib/validation";

type Row = Record<string, unknown> & { id?: string; salon_id?: string; name?: string; created_at?: string };
const ImageUpload = (props: React.ComponentProps<typeof BaseImageUpload>) => <BaseImageUpload {...props} authScope="salon" />;
type Salon = Row & { slug?: string; status?: string; subscription_status?: string; description?: string; neighborhood?: string; email?: string; phone?: string; address_street?: string; address_city?: string; address_state?: string; address_zip?: string; cover_photo_url?: string; gallery_photos?: string[]; hours?: Record<string,string>; languages?: string[]; trust_info?: Record<string,boolean>; media_consent?: boolean; notification_preferences?: Record<string,boolean>; rating_overall?: number; review_count?: number; subscription_tier?: string; stripe_account_id?: string };

const fallbackPhotos = ["/images/braids-cornrows.jpg","/images/braids-knotless.jpg","/images/braids-box.jpg","/images/hero-braids.jpg"];
const days = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];
export default function OwnerDashboardApp({ section }: { section: DashboardSection; preview?: boolean }) {
  const [loading,setLoading]=useState(true); const [error,setError]=useState(""); const [notice,setNotice]=useState("");
  const [salon,setSalon]=useState<Salon|null>(null); const [bookings,setBookings]=useState<Row[]>([]); const [reviews,setReviews]=useState<Row[]>([]); const [styles,setStyles]=useState<Row[]>([]); const [stylists,setStylists]=useState<Row[]>([]); const [products,setProducts]=useState<Row[]>([]); const [promotions,setPromotions]=useState<Row[]>([]); const [subscription,setSubscription]=useState<Row|null>(null);
  const [notifications,setNotifications]=useState<Row[]>([]);
  const [selectedStyle,setSelectedStyle]=useState<string|null>(null); const [selectedStylist,setSelectedStylist]=useState<string|null>(null); const [selectedProduct,setSelectedProduct]=useState<string|null>(null);

  useEffect(() => {
    let live = true;
    let removeRealtime: (() => Promise<void>) | null = null;

    async function loadDashboard() {
      const session = await Promise.race([getSessionForScope("salon"), new Promise<null>((resolve) => window.setTimeout(() => resolve(null), 2500))]);
      const userId = session?.user?.id || "";
      if (!live) return;
      if (!userId) {
        setError("Sign in with your salon-owner account. Admin and salon sessions are kept separate, so an admin login will not replace this session.");
        setLoading(false);
        return;
      }
      const { data: s, error: sErr } = await supabase.from("salons").select("*").eq("user_id", userId).limit(1).maybeSingle();
      if (!live) return;
      if (sErr || !s) {
        setError(sErr?.message || "This session is not linked to a salon-owner account. Use the salon-owner login for this dashboard.");
        setLoading(false);
        return;
      }
      setSalon(s as Salon);
      const results = await Promise.all(["bookings", "reviews", "styles", "stylists", "salon_products", "salon_promotions", "subscriptions", "notifications"].map((table) => supabase.from(table).select("*").eq("salon_id", s.id).order("created_at", { ascending: false })));
      if (!live) return;
      setBookings((results[0].data || []) as Row[]); setReviews((results[1].data || []) as Row[]); setStyles((results[2].data || []) as Row[]); setStylists((results[3].data || []) as Row[]);
      setProducts((results[4].data || []) as Row[]); setPromotions((results[5].data || []) as Row[]); setSubscription(((results[6].data || [])[0] || null) as Row | null); setNotifications((results[7].data || []) as Row[]);
      setSelectedStyle(results[2].data?.[0]?.id || null); setSelectedStylist(results[3].data?.[0]?.id || null); setSelectedProduct(results[4].data?.[0]?.id || null); setLoading(false);

      removeRealtime = subscribeToOwnerUpdates({
        client: supabase,
        salonId: s.id,
        onNotification: (row) => { if (live) setNotifications((current) => [row as Row, ...current]); },
        onBooking: (row) => { if (live) setBookings((current) => [row as Row, ...current]); },
        onStatus: (status) => { if (status === "CHANNEL_ERROR" && live) console.error("Salon realtime channel failed", { salonId: s.id, status }); },
      });
      if (!live && removeRealtime) await removeRealtime();
    }

    void loadDashboard().catch((loadError) => {
      if (!live) return;
      console.error("Salon dashboard load failed", loadError);
      setError(loadError instanceof Error ? loadError.message : "Unable to load the dashboard.");
      setLoading(false);
    });

    return () => {
      live = false;
      if (removeRealtime) void removeRealtime();
    };
  }, []);

  async function updateSalon(patch: Record<string,unknown>) { if(!salon?.id)return;const safePatch={...patch};if("email" in safePatch){if(!isValidEmail(safePatch.email)){setNotice("Please enter a valid email address (name@example.com).");return;}safePatch.email=normalizeEmail(safePatch.email);}if("phone" in safePatch&&String(safePatch.phone||"")){if(!isValidUsPhone(safePatch.phone)){setNotice("Please enter a US phone number.");return;}safePatch.phone=normalizeUsPhone(safePatch.phone);}const {error:updateError}=await supabase.from("salons").update(safePatch).eq("id",salon.id); if(updateError){setNotice(updateError.message);return;} setSalon(current=>current?{...current,...safePatch}:current);setNotice("Changes saved to your public salon page."); }
  async function saveRecord(table:string, values:Record<string,unknown>, id?:string) { if(!salon?.id)return null; const query=id?supabase.from(table).update(values).eq("id",id).select().single():supabase.from(table).insert({...values,salon_id:salon.id}).select().single(); const {data,error:saveError}=await query; if(saveError){setNotice(saveError.message);return null;} setNotice("Saved successfully.");return data as Row; }
  async function removeRecord(table:string,id:string,setter:React.Dispatch<React.SetStateAction<Row[]>>) { const {error:deleteError}=await supabase.from(table).delete().eq("id",id); if(deleteError){setNotice(deleteError.message);return;}setter(current=>current.filter(row=>row.id!==id));setNotice("Removed."); }

  if(loading)return <div className="min-h-screen bg-cream p-10 text-center text-plum">Loading your salon workspace…</div>;
  if(error)return <div className="flex min-h-screen items-center justify-center bg-cream p-5"><div className="max-w-md rounded-[18px] border border-plum/10 bg-white p-8 text-center"><h1 className="font-serif text-3xl text-plum">Owner dashboard</h1><p className="mt-3 text-sm text-ink/70">{error}</p><Link href="/salon/login" className="mt-5 inline-flex rounded-[9px] bg-magenta px-5 py-3 text-sm font-bold text-white">Sign in</Link></div></div>;
  if(!salon)return null;
  if(salon.status?.toLowerCase()!=="active")return <div className="flex min-h-screen items-center justify-center bg-cream p-5"><div className="max-w-xl rounded-[22px] border border-plum/10 bg-white p-9 text-center shadow-[0_20px_60px_rgba(26,18,32,.08)]"><div className="mx-auto grid h-16 w-16 place-items-center rounded-full bg-blush text-plum"><Clock3 /></div><h1 className="mt-5 font-serif text-4xl font-semibold text-plum">Your application is under review</h1><p className="mt-4 leading-7 text-ink/70">Your salon has been saved, but the owner dashboard stays locked until Girlz Culture approves and activates your store. We’ll email you as soon as the review is complete.</p><Link href="/salon/application-submitted" className="mt-6 inline-flex rounded-[9px] bg-magenta px-6 py-3 font-bold text-white">View next steps</Link></div></div>;

  const plan=normalizePlan(subscription?.tier||salon.subscription_tier);
  const subscriptionActive=isSubscriptionActive(subscription?.status,subscription?.current_period_end);
  const context={salon,bookings,reviews,styles,stylists,products,promotions,subscription,plan,subscriptionActive,selectedStyle,selectedStylist,selectedProduct,setSelectedStyle,setSelectedStylist,setSelectedProduct,setStyles,setStylists,setProducts,setPromotions,setBookings,updateSalon,saveRecord,removeRecord,setNotice};
  return <OwnerDashboardShell section={section} salonName={salon.name||"Your Salon"} salonSlug={salon.slug||""} avatar={stylists[0]?.avatar_url as string|undefined} notifications={notifications}>{notice?<div role="status" className="mb-4 flex items-center justify-between rounded-[10px] border border-magenta/20 bg-blush/45 px-4 py-3 text-xs text-plum"><span>{notice}</span><button onClick={()=>setNotice("")}>×</button></div>:null}<DashboardContent section={section} context={context}/></OwnerDashboardShell>;
}

type Ctx = {salon:Salon;bookings:Row[];reviews:Row[];styles:Row[];stylists:Row[];products:Row[];promotions:Row[];subscription:Row|null;plan:SubscriptionPlan;subscriptionActive:boolean;selectedStyle:string|null;selectedStylist:string|null;selectedProduct:string|null;setSelectedStyle:(id:string|null)=>void;setSelectedStylist:(id:string|null)=>void;setSelectedProduct:(id:string|null)=>void;setStyles:React.Dispatch<React.SetStateAction<Row[]>>;setStylists:React.Dispatch<React.SetStateAction<Row[]>>;setProducts:React.Dispatch<React.SetStateAction<Row[]>>;setPromotions:React.Dispatch<React.SetStateAction<Row[]>>;setBookings:React.Dispatch<React.SetStateAction<Row[]>>;updateSalon:(patch:Record<string,unknown>)=>Promise<void>;saveRecord:(table:string,values:Record<string,unknown>,id?:string)=>Promise<Row|null>;removeRecord:(table:string,id:string,setter:React.Dispatch<React.SetStateAction<Row[]>>)=>Promise<void>;setNotice:(text:string)=>void};

function DashboardContent({section,context:c}:{section:DashboardSection;context:Ctx}){
  if(section==="subscription")return <SubscriptionV2 c={c}/>;
  if(!c.subscriptionActive)return <SubscriptionRequired c={c}/>;
  if(section==="promotions"&&!hasPlanFeature(c.plan,"promotions"))return <UpgradeRequired feature="Promotions" plan="Growth"/>;
  if(section==="overview")return <Overview c={c}/>; if(section==="my-page")return <MyPage c={c}/>; if(section==="photos")return <Photos c={c}/>; if(section==="styles")return <Styles c={c}/>; if(section==="stylists")return <Stylists c={c}/>; if(section==="products")return <Products c={c}/>; if(section==="availability")return <Availability c={c}/>; if(section==="bookings")return <Bookings c={c}/>; if(section==="reviews")return <Reviews c={c}/>; if(section==="earnings")return <Earnings c={c}/>; if(section==="promotions")return <Promotions c={c}/>; return <SettingsPage c={c}/>;
}

function SubscriptionRequired({c}:{c:Ctx}){return <div className="mx-auto max-w-3xl py-16 text-center"><span className="mx-auto grid h-16 w-16 place-items-center rounded-full bg-blush text-magenta"><Crown size={30}/></span><h1 className="mt-5 font-serif text-4xl font-semibold text-plum">Activate your salon plan</h1><p className="mx-auto mt-4 max-w-xl text-sm leading-7 text-ink/65">Your salon is approved, but the business workspace remains locked until a subscription is active. Your selected {c.plan} plan can be activated in Stripe test mode.</p><Link href="/salon/dashboard/subscription" className="mt-7 inline-flex rounded-[9px] bg-magenta px-7 py-3.5 text-sm font-bold text-white">Activate subscription</Link></div>}
function UpgradeRequired({feature,plan}:{feature:string;plan:SubscriptionPlan}){return <div className="mx-auto max-w-3xl py-16 text-center"><span className="mx-auto grid h-16 w-16 place-items-center rounded-full bg-blush text-magenta"><Sparkles size={30}/></span><h1 className="mt-5 font-serif text-4xl font-semibold text-plum">Upgrade to unlock {feature}</h1><p className="mx-auto mt-4 max-w-xl text-sm leading-7 text-ink/65">This feature is available on the {plan} and Premium plans. Upgrade securely from your subscription page.</p><Link href="/salon/dashboard/subscription" className="mt-7 inline-flex rounded-[9px] bg-magenta px-7 py-3.5 text-sm font-bold text-white">Compare plans</Link></div>}

function SubscriptionV2({c}:{c:Ctx}){const [busy,setBusy]=useState("");async function action(path:string,plan?:SubscriptionPlan){setBusy(plan||"portal");try{const {data:{session}}=await supabase.auth.getSession();if(!session)throw new Error("Please sign in again.");const response=await fetch(path,{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${session.access_token}`},body:JSON.stringify(plan?{plan}:{})});const body=await response.json();if(!response.ok)throw new Error(body.error||"Unable to open Stripe checkout.");if(body.url)window.location.assign(body.url);}catch(error){c.setNotice(error instanceof Error?error.message:"Unable to continue.");setBusy("");}}return <><Title title="Subscription" subtitle="Choose the plan that matches your growth goals. Payments are in Stripe test mode."/><div className="mb-4 rounded-[10px] border border-amber/30 bg-amber/10 px-4 py-3 text-xs text-ink/70"><b>TEST MODE:</b> No real charges are processed while Girlz Culture is in pre-launch testing.</div><div className="grid gap-4 lg:grid-cols-3">{PLAN_ORDER.map(name=>{const plan=SUBSCRIPTION_PLANS[name];const current=c.plan===name&&c.subscriptionActive;return <Panel key={name} className={name==="Growth"?"border-magenta":""}><div className="flex items-center justify-between"><h2 className="font-serif text-2xl text-plum">{name}</h2>{name==="Growth"?<span className="rounded-full bg-magenta px-2 py-1 text-[8px] font-bold uppercase text-white">Most Popular</span>:null}</div><p className="mt-3 font-serif text-3xl font-semibold">${plan.monthlyPrice.toFixed(2)}<span className="font-sans text-[10px] font-normal"> / month</span></p><p className="mt-2 min-h-10 text-[11px] text-ink/60">{plan.description}</p><ul className="mt-4 space-y-2 text-[10px]">{plan.features.map(feature=><li key={feature}>✓ {feature}</li>)}</ul><button disabled={Boolean(busy)||current} onClick={()=>void action("/api/stripe/subscription/checkout",name)} className={`mt-6 min-h-11 w-full rounded-[8px] text-xs font-bold disabled:opacity-60 ${current?"border border-green-500 text-green-700":"bg-magenta text-white"}`}>{current?"Current active plan":busy===name?"Opening checkout…":`Choose ${name}`}</button></Panel>})}</div>{c.subscription?.stripe_customer_id?<button disabled={Boolean(busy)} onClick={()=>void action("/api/stripe/portal")} className="mt-5 rounded-[8px] border border-magenta px-5 py-3 text-xs font-bold text-magenta">{busy==="portal"?"Opening billing…":"Manage billing and cancellation"}</button>:null}</>}

function Title({title,subtitle,action}:{title:string;subtitle:string;action?:React.ReactNode}){return <div className="mb-5 flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between"><div><h1 className="font-serif text-[36px] font-semibold leading-none tracking-[-.035em] text-plum sm:text-[48px]">{title}</h1><p className="mt-2 text-sm text-ink/65">{subtitle}</p></div>{action}</div>}
function Panel({children,className=""}:{children:React.ReactNode;className?:string}){return <section className={`min-w-0 rounded-[13px] border border-plum/10 bg-white/70 p-4 shadow-[0_5px_18px_rgba(26,18,32,.035)] sm:p-5 ${className}`}>{children}</section>}
function Metric({label,value,icon:Icon=Eye}:{label:string;value:string|number;trend?:string;icon?:React.ComponentType<{size?:number}>}){return <Panel><div className="flex items-center justify-between"><div><p className="text-xs text-ink/70">{label}</p><p className="mt-1 font-serif text-[28px] font-semibold">{value}</p></div><span className="flex h-11 w-11 items-center justify-center rounded-full bg-blush text-magenta"><Icon size={22}/></span></div></Panel>}
function MiniLine(){return <p className="rounded-[8px] border border-dashed border-plum/15 bg-cream/50 p-4 text-center text-[10px] text-ink/50">No historical trend data yet.</p>}

function Overview({c}:{c:Ctx}){
  const completed=c.bookings.filter(b=>String(b.status).toLowerCase()==="completed");
  const revenue=completed.reduce((sum,b)=>sum+Number(b.estimated_total||0),0);
  const upcoming=c.bookings.filter(b=>new Date(String(b.appointment_datetime||0))>new Date()).slice(0,3);
  const completion=Math.round([c.salon.name,c.salon.description,c.salon.phone,c.salon.address_street,c.salon.cover_photo_url,c.styles.length,c.stylists.length].filter(Boolean).length/7*100);
  return <><Title title="Salon Owner Dashboard" subtitle="Run your business with confidence."/><div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4"><Metric label="Profile Views" value={Number(c.salon.profile_views||0)}/><Metric label="Booking Requests" value={c.bookings.length} icon={CalendarDays}/><Metric label="New Customers" value={new Set(c.bookings.map(b=>b.customer_id).filter(Boolean)).size} icon={UsersRound}/><Metric label="Completed Booking Value" value={`$${revenue.toLocaleString()}`} icon={CircleDollarSign}/></div><div className="mt-4 grid gap-4 xl:grid-cols-[.75fr_1.5fr_.8fr]"><Panel><h2 className="font-serif text-xl text-plum">Profile Completion</h2><p className="mt-3 text-sm">Complete your profile to attract more clients and grow your brand.</p><div className="mt-5 flex items-center gap-3"><div className="h-2 flex-1 rounded-full bg-blush"><div className="h-full rounded-full bg-magenta" style={{width:`${completion}%`}}/></div><b>{completion}%</b></div><Link href="/salon/dashboard/my-page" className="mt-6 inline-flex text-xs font-bold text-magenta">Finish setup →</Link></Panel><Panel><div className="flex justify-between"><h2 className="font-serif text-xl text-plum">Upcoming Appointments</h2><Link href="/salon/dashboard/bookings" className="text-xs text-magenta">View all</Link></div><div className="mt-3 divide-y divide-plum/10">{upcoming.map((b,i)=><div key={b.id||i} className="grid grid-cols-[75px_1fr_auto] gap-3 py-3 text-xs"><span>{dateText(b.appointment_datetime)}</span><span><b>{styleName(c,b.style_id)}</b><br/><span className="text-ink/55">{stylistName(c,b.stylist_id)}</span></span><Status value={String(b.status||"Requested")}/></div>)}{!upcoming.length?<Empty text="No upcoming appointments."/>:null}</div></Panel><Panel><h2 className="font-serif text-xl text-plum">Recent Reviews</h2>{c.reviews.slice(0,2).map((r,i)=><div key={r.id||i} className="mt-3 border-t border-plum/10 pt-3 text-xs"><Stars value={Number(r.rating_overall||0)}/>{r.written_review?<p className="mt-2 line-clamp-3">{String(r.written_review)}</p>:null}</div>)}{!c.reviews.length?<Empty text="Reviews will appear after completed bookings."/>:null}</Panel></div><div className="mt-4 grid gap-4 lg:grid-cols-[.7fr_1.3fr]"><Panel><div className="flex items-center gap-3"><Crown className="text-magenta"/><div><p className="text-xs">Subscription</p><h2 className="font-serif text-xl text-plum">{String(c.subscription?.subscription_tier||c.salon.subscription_tier||"No")} Plan</h2></div></div><Link href="/salon/dashboard/subscription" className="mt-4 inline-flex text-xs font-bold text-magenta">Manage subscription →</Link></Panel><Panel><h2 className="font-serif text-xl text-plum">Quick Actions</h2><div className="mt-4 grid grid-cols-3 gap-2 sm:grid-cols-5">{[["Add Photos","photos",ImagePlus],["Availability","availability",CalendarDays],["Promotion","promotions",Megaphone],["Add Stylist","stylists",UserPlus],["Add Product","products",Package]].map(([label,path,Icon])=><Link key={path as string} href={`/salon/dashboard/${path}`} className="flex min-h-24 flex-col items-center justify-center gap-2 rounded-[10px] border border-plum/10 bg-cream/40 text-center text-[10px] font-semibold text-ink"><Icon size={25} className="text-magenta"/>{label as string}</Link>)}</div></Panel></div></>;
}

function MyPage({c}:{c:Ctx}){const [gallery,setGallery]=useState<string[]>(Array.isArray(c.salon.gallery_photos)?c.salon.gallery_photos:[]);const [cover,setCover]=useState(c.salon.cover_photo_url||"");async function submit(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);await c.updateSalon({name:f.get("name"),description:f.get("description"),address_street:f.get("address"),neighborhood:f.get("neighborhood"),phone:f.get("phone"),email:f.get("email"),languages:String(f.get("languages")||"").split(",").map(x=>x.trim()).filter(Boolean).slice(0,5),trust_info:Object.fromEntries(["licensed_professionals","clean_safe","women_owned","appointment_only"].map(k=>[k,f.get(k)==="on"])),media_consent:f.get("consent")==="on",cover_photo_url:cover,gallery_photos:gallery});}return <><Title title="My Page" subtitle="Update your salon information. This information appears on your public salon page." action={<div className="flex gap-2"><Link href={`/salon/${c.salon.slug}`} className="rounded-[8px] border border-magenta px-4 py-3 text-xs font-bold text-magenta">Preview your public page</Link><button form="my-page-form" className="rounded-[8px] bg-magenta px-6 py-3 text-xs font-bold text-white">Save changes</button></div>}/><form id="my-page-form" onSubmit={submit} className="grid gap-4 xl:grid-cols-2"><Panel><h2 className="font-serif text-xl text-plum">Business Information</h2><div className="mt-4 grid gap-4 sm:grid-cols-2"><Field label="Business Name" name="name" defaultValue={c.salon.name} required wide/><TextArea label="About / Description" name="description" defaultValue={c.salon.description} wide/><Field label="Address" name="address" defaultValue={c.salon.address_street}/><Field label="Neighborhood" name="neighborhood" defaultValue={c.salon.neighborhood}/><Field label="Phone" name="phone" defaultValue={c.salon.phone}/><Field label="Email" name="email" defaultValue={c.salon.email} type="email"/><Field label="Languages Spoken" name="languages" defaultValue={(c.salon.languages||[]).join(", ")} wide/><div className="sm:col-span-2"><p className="mb-2 text-xs font-bold">Trust Info</p><div className="grid grid-cols-2 gap-2 sm:grid-cols-4">{[["licensed_professionals","Licensed Professionals"],["clean_safe","Clean & Safe Studio"],["women_owned","Women-Owned"],["appointment_only","By Appointment Only"]].map(([key,label])=><label key={key} className="flex min-h-20 flex-col justify-between rounded-[9px] border border-plum/10 p-3 text-[10px] font-semibold"><span>{label}</span><input name={key} type="checkbox" defaultChecked={c.salon.trust_info?.[key]} className="accent-magenta"/></label>)}</div></div></div></Panel><Panel><h2 className="font-serif text-xl text-plum">Photos / Media</h2><div className="mt-4"><ImageUpload bucket="salon-photos" folder={`salons/${c.salon.id}`} label="Cover Photo (Required)" value={cover} onChange={v=>setCover(typeof v==="string"?v:"")} helperText="This is the main image at the top of your public page."/></div><div className="mt-5"><ImageUpload bucket="salon-photos" multiple maxFiles={12} folder={`salons/${c.salon.id}/gallery`} label="Gallery" value={gallery} onChange={v=>setGallery(Array.isArray(v)?v:[])} helperText="Showcase your work and your space."/></div><label className="mt-5 flex gap-3 text-xs font-semibold"><input name="consent" required type="checkbox" defaultChecked={Boolean(c.salon.media_consent)} className="accent-magenta"/>I confirm I have permission to use these images and the right to display them.</label></Panel></form></>}

function Photos({c}:{c:Ctx}){const [cover,setCover]=useState(c.salon.cover_photo_url||"");const [gallery,setGallery]=useState<string[]>(Array.isArray(c.salon.gallery_photos)?c.salon.gallery_photos:[]);return <><Title title="Photos" subtitle="Manage the media that tells your salon’s story." action={<button onClick={()=>c.updateSalon({cover_photo_url:cover,gallery_photos:gallery,media_consent:true})} className="rounded-[8px] bg-magenta px-6 py-3 text-xs font-bold text-white">Save media</button>}/><div className="grid gap-4 xl:grid-cols-[.7fr_1.3fr]"><Panel><ImageUpload bucket="salon-photos" folder={`salons/${c.salon.id}`} label="Cover Photo" value={cover} onChange={v=>setCover(typeof v==="string"?v:"")} helperText="JPG or PNG, maximum 2MB after optimization."/></Panel><Panel><ImageUpload bucket="salon-photos" multiple maxFiles={16} folder={`salons/${c.salon.id}/gallery`} label="Media Library" value={gallery} onChange={v=>setGallery(Array.isArray(v)?v:[])} helperText="Upload, remove, and reorder salon work photos."/><label className="mt-5 flex gap-3 text-xs font-semibold"><input type="checkbox" defaultChecked className="accent-magenta"/>I confirm I have permission to use these images and the right to display them.</label></Panel></div></>}

function Styles({c}:{c:Ctx}){const active=c.styles.find(s=>s.id===c.selectedStyle)||null;async function submit(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const priced=(key:string)=>String(f.get(key)||"").split("\n").map(line=>{const [label,price_add]=line.split("|");return {label:label?.trim(),price_add:Number(price_add||0)}}).filter(x=>x.label);const saved=await c.saveRecord("styles",{name:f.get("name"),category:f.get("category"),description:f.get("description"),duration_min_hours:Number(f.get("duration_min")),duration_max_hours:Number(f.get("duration_max")),base_price:Number(f.get("base_price")),price_display_min:Number(f.get("base_price")),price_display_max:Number(f.get("max_price")||f.get("base_price")),size_options:priced("sizes"),length_options:priced("lengths"),addons:priced("addons"),included_items:String(f.get("included")||"").split(",").map(x=>x.trim()).filter(Boolean)},active?.id);if(saved){const materials=String(f.get("materials")||"").split("\n").map(line=>{const [name,price,longevity,quality_note]=line.split("|");return {style_id:saved.id,name:name?.trim(),price:Number(price||0),longevity:longevity?.trim(),quality_note:quality_note?.trim()}}).filter(x=>x.name);if(saved.id){await supabase.from("style_materials").delete().eq("style_id",saved.id);if(materials.length)await supabase.from("style_materials").insert(materials)}c.setStyles(rows=>active?rows.map(r=>r.id===active.id?saved:r):[saved,...rows]);c.setSelectedStyle(saved.id||null)}}return <><Title title="Styles & Pricing" subtitle="Manage your signature styles, pricing, options, and inclusions." action={<button onClick={()=>c.setSelectedStyle(null)} className="rounded-[8px] bg-magenta px-6 py-3 text-xs font-bold text-white"><Plus className="mr-1 inline" size={16}/>Add Style</button>}/><div className="grid gap-4 xl:grid-cols-[.72fr_1.28fr]"><Panel><h2 className="font-serif text-xl text-plum">Your Styles</h2><div className="mt-3 space-y-2">{c.styles.map((style,i)=>{const min=Number(style.duration_min_hours||0);const max=Number(style.duration_max_hours||0);const duration=min&&max?`${min}–${max} hrs`:"Duration not set";return <button key={style.id} onClick={()=>c.setSelectedStyle(style.id||null)} className={`grid w-full grid-cols-[64px_1fr_auto] gap-3 rounded-[10px] border p-2 text-left ${c.selectedStyle===style.id?"border-magenta bg-blush/30":"border-plum/10"}`}><SafeImage src={(style.photos as string[])?.[0]} fallbackSrc={fallbackPhotos[i%fallbackPhotos.length]} alt={style.name||"Style"} className="h-16 w-16 rounded-[8px] object-cover"/><span><b className="font-serif text-base">{style.name}</b><span className="mt-1 block text-[10px] text-ink/55">{String(style.category||"Uncategorized")} • {duration}</span></span><span className="text-right text-[10px]">From<br/><b className="text-sm">${Number(style.price_display_min||style.base_price||0)}</b></span></button>})}{!c.styles.length?<Empty text="Add your first service."/>:null}</div></Panel><Panel><h2 className="font-serif text-xl text-plum">{active?"Edit Style":"Add Style"}</h2><form key={active?.id||"new"} onSubmit={submit} className="mt-4 grid gap-4 sm:grid-cols-2"><Field label="Style Name" name="name" defaultValue={active?.name} required/><Field label="Category" name="category" defaultValue={active?.category||""}/><TextArea label="Description" name="description" defaultValue={active?.description} wide/><Field label="Duration Min (hrs)" name="duration_min" type="number" defaultValue={active?.duration_min_hours||0}/><Field label="Duration Max (hrs)" name="duration_max" type="number" defaultValue={active?.duration_max_hours||0}/><Field label="Base Price" name="base_price" type="number" defaultValue={active?.base_price||0}/><Field label="Maximum Price" name="max_price" type="number" defaultValue={active?.price_display_max||active?.base_price||0}/><TextArea label="Size Options — one per line: Name|Price Add" name="sizes" defaultValue={optionText(active?.size_options)} /><TextArea label="Length Options — one per line: Name|Price Add" name="lengths" defaultValue={optionText(active?.length_options)}/><TextArea label="Add-ons — one per line: Name|Price" name="addons" defaultValue={optionText(active?.addons)}/><TextArea label="Hair / Material — Name|Price|Longevity|Quality" name="materials" defaultValue=""/><TextArea label="What’s Included — comma separated" name="included" defaultValue={Array.isArray(active?.included_items)?(active?.included_items as string[]).join(", "):""} wide/><button className="sm:col-span-2 min-h-11 rounded-[8px] bg-magenta text-xs font-bold text-white">Save Changes</button></form></Panel></div></>}

function Stylists({c}:{c:Ctx}){const active=c.stylists.find(s=>s.id===c.selectedStylist)||null;const [avatar,setAvatar]=useState(String(active?.avatar_url||""));const [portfolio,setPortfolio]=useState<string[]>(Array.isArray(active?.photos)?active?.photos as string[]:[]);async function submit(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const saved=await c.saveRecord("stylists",{name:f.get("name"),bio:f.get("bio"),specialties:String(f.get("specialties")||"").split(",").map(x=>x.trim()).filter(Boolean),years_experience:Number(f.get("years")),avatar_url:avatar,photos:portfolio,is_active:true},active?.id);if(saved){c.setStylists(rows=>active?rows.map(r=>r.id===active.id?saved:r):[saved,...rows]);c.setSelectedStylist(saved.id||null)}}return <><Title title="Stylists" subtitle="Manage your talented team and their expertise." action={<button onClick={()=>{c.setSelectedStylist(null);setAvatar("");setPortfolio([])}} className="rounded-[8px] bg-magenta px-6 py-3 text-xs font-bold text-white"><Plus className="mr-1 inline" size={16}/>Add Stylist</button>}/><div className="flex gap-3 overflow-x-auto pb-3">{c.stylists.map((stylist,i)=>{const rating=Number(stylist.rating||0);return <button key={stylist.id} onClick={()=>{c.setSelectedStylist(stylist.id||null);setAvatar(String(stylist.avatar_url||""));setPortfolio(Array.isArray(stylist.photos)?stylist.photos as string[]:[])}} className={`min-w-[170px] rounded-[11px] border p-3 text-left ${active?.id===stylist.id?"border-magenta bg-blush/30":"border-plum/10 bg-white"}`}><SafeImage src={stylist.avatar_url as string} fallbackSrc={fallbackPhotos[i%fallbackPhotos.length]} alt={stylist.name||"Stylist"} className="h-16 w-16 rounded-full object-cover"/><p className="mt-2 font-serif text-lg">{stylist.name}</p>{rating>0?<Stars value={rating}/>:<p className="mt-1 text-[10px] text-ink/55">New</p>}<p className="mt-1 text-[10px] text-ink/55">{Number(stylist.years_experience||0)>0?`${Number(stylist.years_experience)} years experience`:"Experience not added"}</p></button>})}</div><Panel><h2 className="font-serif text-xl text-plum">{active?"Edit Stylist":"Add Stylist"}</h2><form key={active?.id||"new"} onSubmit={submit} className="mt-4 grid gap-4 xl:grid-cols-[.75fr_1fr_1.3fr]"><div><ImageUpload bucket="stylist-photos" folder={`stylists/${active?.id||"new"}`} label="Profile Photo" value={avatar} onChange={v=>setAvatar(typeof v==="string"?v:"")}/></div><div className="space-y-4"><Field label="Name" name="name" defaultValue={active?.name} required/><TextArea label="Bio / Description" name="bio" defaultValue={active?.bio}/><Field label="Specialties (comma separated)" name="specialties" defaultValue={Array.isArray(active?.specialties)?(active?.specialties as string[]).join(", "):""}/><Field label="Years of Experience" name="years" type="number" defaultValue={active?.years_experience||0}/><button className="min-h-11 w-full rounded-[8px] bg-magenta text-xs font-bold text-white">Save Changes</button></div><ImageUpload bucket="stylist-photos" multiple maxFiles={10} folder={`stylists/${active?.id||"new"}/portfolio`} label="Work Portfolio" value={portfolio} onChange={v=>setPortfolio(Array.isArray(v)?v:[])}/></form></Panel></>}

function Products({c}:{c:Ctx}){const active=c.products.find(p=>p.id===c.selectedProduct)||null;const [photo,setPhoto]=useState(String(active?.photo_url||""));async function submit(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const saved=await c.saveRecord("salon_products",{name:f.get("name"),description:f.get("description"),price:Number(f.get("price")),photo_url:photo,is_visible:f.get("visible")==="on",in_person_only:true},active?.id);if(saved){c.setProducts(rows=>active?rows.map(r=>r.id===active.id?saved:r):[saved,...rows]);c.setSelectedProduct(saved.id||null)}}return <><Title title="Products" subtitle="Advertise products for in-person purchase at your salon." action={<button onClick={()=>{c.setSelectedProduct(null);setPhoto("")}} className="rounded-[8px] bg-magenta px-6 py-3 text-xs font-bold text-white"><Plus className="mr-1 inline" size={16}/>Add Product</button>}/><div className="mb-4 rounded-[9px] border border-blue-200 bg-blue-50 px-4 py-3 text-xs text-blue-900">ⓘ These products are advertised for in-person purchase only and appear on your salon’s public page. No online checkout.</div><div className="grid gap-4 xl:grid-cols-[1.35fr_.65fr]"><div className="grid grid-cols-2 gap-3 md:grid-cols-3 xl:grid-cols-4">{c.products.map((p,i)=><button key={p.id} onClick={()=>{c.setSelectedProduct(p.id||null);setPhoto(String(p.photo_url||""))}} className="overflow-hidden rounded-[10px] border border-plum/10 bg-white text-left"><SafeImage src={p.photo_url as string} fallbackSrc={fallbackPhotos[i%fallbackPhotos.length]} alt={p.name||"Product"} className="aspect-square w-full object-cover"/><div className="p-3"><b className="text-sm">{p.name}</b><p className="mt-1 line-clamp-2 text-[10px] text-ink/60">{String(p.description||"")}</p><p className="mt-2 font-semibold">${Number(p.price||0).toFixed(2)}</p></div></button>)}{!c.products.length?<Empty text="Add products sold at your salon."/>:null}</div><Panel><h2 className="font-serif text-xl text-plum">Add / Edit Product</h2><form key={active?.id||"new"} onSubmit={submit} className="mt-4 space-y-4"><ImageUpload bucket="salon-photos" folder={`salons/${c.salon.id}/products`} label="Product Photo" value={photo} onChange={v=>setPhoto(typeof v==="string"?v:"")}/><Field label="Name" name="name" defaultValue={active?.name}/><TextArea label="Description" name="description" defaultValue={active?.description}/><Field label="Price (USD)" name="price" type="number" defaultValue={active?.price||0}/><label className="flex items-center gap-2 text-xs"><input type="checkbox" name="visible" defaultChecked={active?.is_visible!==false} className="accent-magenta"/>Visible on Public Page</label><button className="min-h-11 w-full rounded-[8px] bg-magenta text-xs font-bold text-white">Save Product</button></form></Panel></div></>}

function Availability({c}:{c:Ctx}){const hours=c.salon.hours||{};async function submit(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);await c.updateSalon({hours:Object.fromEntries(days.map(day=>[day,String(f.get(day)||"Closed")]))})}return <><Title title="Availability & Calendar" subtitle="Manage your availability, store hours, and appointments with ease."/><div className="grid gap-4 xl:grid-cols-[1.35fr_.65fr]"><Panel><div className="grid grid-cols-7 border-b border-plum/10 pb-3 text-center text-[10px] font-semibold">{days.map(day=><span key={day}>{day}</span>)}</div><div className="relative mt-3 grid min-h-[430px] grid-cols-7 border-l border-t border-plum/10">{days.map(day=><div key={day} className="border-b border-r border-plum/10 bg-[linear-gradient(to_bottom,transparent_49px,rgba(91,26,107,.08)_50px)] [background-size:100%_50px]"/>)}{c.bookings.slice(0,8).map((b,i)=><div key={b.id||i} style={{left:`${(i%7)*14.285+1}%`,top:`${45+(i%5)*66}px`,width:"12.2%"}} className="absolute rounded-[7px] border border-magenta/30 bg-blush/75 p-2 text-[8px]"><b>{styleName(c,b.style_id)}</b><br/>{dateText(b.appointment_datetime)}</div>)}</div></Panel><div className="space-y-4"><Panel><h2 className="font-serif text-xl text-plum">Store Hours</h2><form onSubmit={submit} className="mt-3 space-y-2">{days.map(day=><label key={day} className="grid grid-cols-[35px_1fr] items-center gap-2 text-xs"><span>{day}</span><input name={day} defaultValue={hours[day]||"Closed"} className="rounded-[7px] border border-plum/10 px-3 py-2"/></label>)}<button className="min-h-10 w-full rounded-[8px] bg-magenta text-xs font-bold text-white">Save hours</button></form></Panel><Panel><h2 className="font-serif text-xl text-plum">Bookable Time Slots</h2><div className="mt-3 grid grid-cols-2 gap-2"><Field label="Slot length" name="slot" defaultValue="30 min"/><Field label="Buffer time" name="buffer" defaultValue="15 min"/></div></Panel><Panel><h2 className="font-serif text-xl text-plum">Per-Stylist Availability</h2><div className="mt-3 space-y-2">{c.stylists.map((s,i)=><div key={s.id} className="flex items-center gap-2 text-xs"><SafeImage src={s.avatar_url as string} fallbackSrc={fallbackPhotos[i%4]} alt={s.name||"Stylist"} className="h-7 w-7 rounded-full object-cover"/><span className="flex-1">{s.name}</span><span className="text-ink/50">Availability not set</span></div>)}{!c.stylists.length?<Empty text="Add a stylist to set individual availability."/>:null}</div></Panel></div></div></>}

function Bookings({c}:{c:Ctx}){const [filter,setFilter]=useState("All");const visible=c.bookings.filter(b=>filter==="All"||String(b.status)===filter);async function status(id:string,value:string){const {error}=await supabase.from("bookings").update({status:value}).eq("id",id);if(error){c.setNotice(error.message);return;}c.setBookings(rows=>rows.map(b=>b.id===id?{...b,status:value}:b));c.setNotice(`Booking marked ${value}.`)}return <><Title title="Bookings & Appointments" subtitle="Manage booking requests, appointments, and client schedule."/><div className="mb-4 flex flex-wrap gap-2">{["All","Requested","Confirmed","Completed","Cancelled"].map(item=><button key={item} onClick={()=>setFilter(item)} className={`rounded-[8px] px-4 py-2 text-xs font-semibold ${filter===item?"bg-plum text-white":"border border-plum/10 bg-white"}`}>{item}</button>)}</div><Panel className="overflow-x-auto"><table className="w-full min-w-[850px] text-left text-xs"><thead><tr className="border-b border-plum/10 text-[9px] uppercase tracking-wider">{["Customer","Style","Stylist","Date / Time","Deposit","Balance","Status","Actions"].map(h=><th key={h} className="px-3 py-3">{h}</th>)}</tr></thead><tbody>{visible.map((b,i)=><tr key={b.id||i} className="border-b border-plum/10"><td className="px-3 py-3">Client {i+1}</td><td className="px-3">{styleName(c,b.style_id)}</td><td className="px-3">{stylistName(c,b.stylist_id)}</td><td className="px-3">{dateText(b.appointment_datetime)}</td><td className="px-3 text-green-700">${Number(b.deposit_amount||0).toFixed(2)}</td><td className="px-3 text-magenta">${Number(b.balance_due||0).toFixed(2)}</td><td className="px-3"><Status value={String(b.status||"Requested")}/></td><td className="px-3"><div className="flex gap-1">{String(b.status)==="Requested"?<><button onClick={()=>status(b.id||"","Confirmed")} className="rounded bg-plum px-2 py-1 text-white">Confirm</button><button onClick={()=>status(b.id||"","Cancelled")} className="rounded border border-magenta px-2 py-1 text-magenta">Decline</button></>:<button onClick={()=>status(b.id||"","Cancelled")} className="text-magenta">Cancel</button>}</div></td></tr>)}</tbody></table>{!visible.length?<Empty text="No bookings in this status."/>:null}</Panel></>}

function Reviews({c}:{c:Ctx}){
  const count=c.reviews.length;
  const rating=count?c.reviews.reduce((sum,review)=>sum+Number(review.rating_overall||0),0)/count:0;
  const distribution=[5,4,3,2,1].map(star=>({star,count:c.reviews.filter(review=>Math.round(Number(review.rating_overall||0))===star).length}));
  return <><Title title="Reviews" subtitle="See what clients are saying about your salon."/><div className="grid gap-4 xl:grid-cols-[1.35fr_.65fr]"><div><Panel><div className="grid gap-4 sm:grid-cols-[.6fr_.6fr_1.2fr]"><div><p className="text-xs font-semibold">Overall Rating</p><p className="mt-2 font-serif text-5xl">{count?rating.toFixed(1):"New"}</p>{count?<Stars value={rating}/>:null}</div><div><p className="text-xs font-semibold">Total Reviews</p><p className="mt-2 font-serif text-5xl">{count}</p></div><div className="space-y-2">{distribution.map(item=>{const percent=count?Math.round(item.count/count*100):0;return <div key={item.star} className="grid grid-cols-[25px_1fr_45px] items-center gap-2 text-[10px]"><span>{item.star}</span><span className="h-1.5 rounded-full bg-blush"><span className="block h-full rounded-full bg-magenta" style={{width:`${percent}%`}}/></span><span>{percent}%</span></div>})}</div></div></Panel><h2 className="mb-3 mt-5 font-serif text-xl text-plum">All Reviews</h2><div className="space-y-3">{c.reviews.map((review,index)=><Panel key={review.id||index}><div className="flex justify-between"><div><b>Verified Client</b><span className="ml-2 rounded-full bg-blush px-2 py-1 text-[8px] text-magenta">Verified</span><Stars value={Number(review.rating_overall||0)}/></div><span className="text-[10px] text-ink/50">{dateText(review.created_at)}</span></div>{review.written_review?<p className="mt-3 text-sm">{String(review.written_review)}</p>:null}<div className="mt-4 flex gap-4 text-xs font-semibold text-magenta"><button onClick={()=>c.setNotice("Open this review from the public salon page to reply.")}>Reply</button><button onClick={async()=>{if(review.id)await supabase.rpc("dispute_review",{target_review_id:review.id});c.setNotice("Review sent for moderation.")}}>Flag / Dispute</button></div></Panel>)}{!c.reviews.length?<Panel><Empty text="Completed-booking reviews will appear here automatically."/></Panel>:null}</div></div><div className="space-y-4"><Panel><h2 className="font-serif text-xl text-plum">Review Response Tips</h2>{["Respond to all reviews","Be professional and personal","Resolve issues constructively"].map(tip=><div key={tip} className="mt-4 flex gap-3 text-xs"><Sparkles size={20} className="text-magenta"/><span><b>{tip}</b><span className="mt-1 block text-ink/60">Keep your response warm, respectful, and on-brand.</span></span></div>)}</Panel><Panel><h2 className="font-serif text-xl text-plum">Review Distribution</h2>{count?<div className="mx-auto mt-5 flex h-36 w-36 items-center justify-center rounded-full border-[18px] border-magenta"><span className="text-center font-serif text-3xl">{count}<span className="block text-[10px]">Total</span></span></div>:<Empty text="No reviews yet."/>}</Panel></div></div></>;
}

function Earnings({c}:{c:Ctx}){const completed=c.bookings.filter(b=>["complete","completed"].includes(String(b.status||"").toLowerCase()));const paidDeposits=c.bookings.filter(b=>["paid","succeeded","complete","completed"].includes(String(b.deposit_status||"").toLowerCase()));const total=completed.reduce((s,b)=>s+Number(b.estimated_total||0),0);const deposits=paidDeposits.reduce((s,b)=>s+Number(b.deposit_amount||0),0);const pending=c.bookings.filter(b=>String(b.payout_status||"").toLowerCase()==="pending").reduce((s,b)=>s+Number(b.deposit_amount||0),0);const now=new Date();const thisMonth=completed.filter(b=>{const d=new Date(String(b.appointment_datetime||b.created_at||""));return !Number.isNaN(d.getTime())&&d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear()}).reduce((s,b)=>s+Number(b.estimated_total||0),0);return <><Title title="Earnings & Payouts" subtitle="Track your earnings, manage payouts, and view your transaction history."/><div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4"><Metric label="Paid Deposits" value={`$${deposits.toLocaleString()}`} icon={CircleDollarSign}/><Metric label="Completed Booking Value" value={`$${total.toLocaleString()}`} icon={CircleDollarSign}/><Metric label="Pending Payouts" value={`$${pending.toLocaleString()}`} icon={Clock3}/><Metric label="Completed This Month" value={`$${thisMonth.toLocaleString()}`} icon={CalendarDays}/></div><div className="mt-4 grid gap-4 xl:grid-cols-[.75fr_.65fr_1.1fr]"><Panel><h2 className="font-serif text-xl text-plum">Payout Account</h2>{c.salon.stripe_account_id?<><p className="mt-4 text-green-700">✓ Account connected</p><p className="mt-2 text-xs text-ink/60">Connection details are managed securely in Stripe.</p></>:<><p className="mt-4 font-semibold">Connect your payout account</p><p className="mt-2 text-xs leading-5 text-ink/65">Connect your Stripe account to receive payouts securely. Girlz Culture never stores your bank details.</p><button onClick={()=>c.setNotice("Stripe Connect requires the platform’s live Stripe credentials before onboarding can begin.")} className="mt-5 min-h-11 w-full rounded-[8px] bg-[linear-gradient(90deg,#5b1a6b,#d6186b)] text-xs font-bold text-white">Connect with Stripe</button></>}</Panel><Panel><h2 className="font-serif text-xl text-plum">Account Status</h2><p className="mt-4 text-sm text-green-700">{c.salon.stripe_account_id?"Account connected":"Not connected"}</p><p className="mt-3 text-xs text-ink/60">{c.salon.stripe_account_id?"Payout timing and account details are available in Stripe.":"Connect Stripe before accepting payouts."}</p></Panel><Panel><h2 className="font-serif text-xl text-plum">Earnings Trend</h2><p className="mt-3 font-serif text-3xl">${total.toLocaleString()}</p><div className="mt-8"><MiniLine/></div></Panel></div><Panel className="mt-4 overflow-x-auto"><h2 className="font-serif text-xl text-plum">Transaction History</h2><table className="mt-3 w-full min-w-[700px] text-left text-xs"><thead><tr>{["Date","Booking","Deposit Amount","Balance","Payment / Payout Status","Payout Date"].map(h=><th className="border-b border-plum/10 py-3" key={h}>{h}</th>)}</tr></thead><tbody>{c.bookings.map((b,i)=><tr key={b.id||i} className="border-b border-plum/10"><td className="py-3">{dateText(b.created_at)}</td><td>Booking #{String(b.confirmation_code||b.id||"").slice(0,8)}</td><td>${Number(b.deposit_amount||0).toFixed(2)}</td><td>${Number(b.balance_due||0).toFixed(2)}</td><td><Status value={String(b.payout_status||b.deposit_status||"Not recorded")}/></td><td>{dateText(b.payout_date)}</td></tr>)}{!c.bookings.length?<tr><td colSpan={6}><Empty text="Transactions will appear after real bookings and payments." /></td></tr>:null}</tbody></table></Panel></>}

function Promotions({c}:{c:Ctx}){
  async function submit(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);const saved=await c.saveRecord("salon_promotions",{title:f.get("title"),description:f.get("description"),discount_label:f.get("discount"),starts_at:f.get("start"),ends_at:f.get("end"),is_active:f.get("active")==="on"});if(saved)c.setPromotions(rows=>[saved,...rows])}
  return <><Title title="Business Growth & Admin" subtitle="Manage promotions, subscription, and account settings."/><div className="grid gap-4 xl:grid-cols-2"><Panel><h2 className="font-serif text-xl text-plum">Create a Deal or Offer</h2><form onSubmit={submit} className="mt-4 grid gap-4 sm:grid-cols-2"><Field label="Title" name="title" placeholder="Describe your offer" wide/><TextArea label="Description" name="description" placeholder="Describe the offer and any terms." wide/><Field label="Discount" name="discount"/><Field label="Start Date" name="start" type="date"/><Field label="End Date" name="end" type="date"/><label className="flex items-center gap-2 text-xs"><input type="checkbox" name="active" className="accent-magenta"/>Activate promotion</label><button className="sm:col-span-2 min-h-11 rounded-[8px] bg-magenta text-xs font-bold text-white">Create Promotion</button></form></Panel><Panel className="bg-blush/35"><Megaphone className="text-magenta"/><h2 className="mt-4 font-serif text-2xl text-plum">Promotion visibility</h2><p className="mt-3 text-sm leading-6 text-ink/65">Published promotions are shown according to your active plan. Performance reporting will remain empty until real views, clicks, and attributed bookings are collected.</p><Link href="/salon/dashboard/subscription" className="mt-5 inline-flex rounded-[8px] border border-magenta px-5 py-3 text-xs font-bold text-magenta">Review plan features</Link></Panel></div><div className="mt-4 grid gap-4 lg:grid-cols-[1.2fr_.8fr]"><Panel><h2 className="font-serif text-xl text-plum">Promotion Performance</h2><div className="mt-4 grid grid-cols-3 gap-3"><Metric label="Views" value={0}/><Metric label="Clicks" value={0}/><Metric label="Bookings" value={0}/></div><p className="mt-4 text-xs text-ink/50">Attribution data has not been collected yet.</p></Panel><Panel><h2 className="font-serif text-xl text-plum">Recent Promotions</h2>{c.promotions.map(p=><div key={p.id} className="mt-3 flex items-center justify-between border-b border-plum/10 pb-3 text-xs"><span><b>{String(p.title||"Promotion")}</b><span className="block text-ink/50">{dateText(p.starts_at)} – {dateText(p.ends_at)}</span></span><Status value={p.is_active?"Active":"Ended"}/></div>)}{!c.promotions.length?<Empty text="Create your first offer."/>:null}</Panel></div></>;
}


function SettingsPage({c}:{c:Ctx}){async function submit(e:FormEvent<HTMLFormElement>){e.preventDefault();const f=new FormData(e.currentTarget);await c.updateSalon({email:f.get("email"),phone:f.get("phone"),notification_preferences:{in_app:f.get("in_app")==="on",email:f.get("email_notifications")==="on",sms:f.get("sms")==="on",reviews:f.get("reviews")==="on",marketing:f.get("marketing")==="on"}})}return <><Title title="Settings" subtitle="Manage login, notifications, and business account details."/><form onSubmit={submit} className="grid gap-4 xl:grid-cols-2"><Panel><h2 className="font-serif text-xl text-plum">Account Details</h2><div className="mt-4 space-y-4"><Field label="Login Email" name="email" type="email" defaultValue={c.salon.email}/><Field label="Business Phone / SMS Number" name="phone" defaultValue={c.salon.phone}/><button type="button" onClick={()=>c.setNotice("A secure password-reset email can be sent from the login screen.")} className="text-xs font-bold text-magenta">Change password</button></div></Panel><Panel><h2 className="font-serif text-xl text-plum">Notification Preferences</h2><div className="mt-4 space-y-3">{[["in_app","In-app booking alerts"],["email_notifications","Email for every booking"],["sms","SMS for every booking"],["reviews","New reviews and replies"],["marketing","Marketing and growth tips"]].map(([key,label])=><label key={key} className="flex items-center justify-between rounded-[9px] border border-plum/10 p-4 text-xs"><span>{label}</span><input type="checkbox" name={key} defaultChecked={c.salon.notification_preferences?.[key==="email_notifications"?"email":key]!==false} className="accent-magenta"/></label>)}</div><button className="mt-5 min-h-11 w-full rounded-[8px] bg-magenta text-xs font-bold text-white">Save Settings</button></Panel></form></>}

function Field({label,name,defaultValue,placeholder,type="text",required=false,wide=false}:{label:string;name:string;defaultValue?:unknown;placeholder?:string;type?:string;required?:boolean;wide?:boolean}){const inputType=name==="phone"?"tel":type;const pattern=inputType==="email"?EMAIL_PATTERN:inputType==="tel"?US_PHONE_PATTERN:undefined;return <label className={`block ${wide?"sm:col-span-2":""}`}><span className="mb-1.5 block text-[10px] font-bold">{label}{required?<span className="text-magenta"> *</span>:null}</span><input name={name} type={inputType} inputMode={inputType==="tel"?"tel":undefined} pattern={pattern} title={inputType==="email"?"Enter a valid email address such as name@example.com":inputType==="tel"?"Please enter a US phone number":undefined} required={required} defaultValue={String(defaultValue??"")} placeholder={placeholder||(inputType==="tel"?"+1 (555) 123-4567":undefined)} step={type==="number"?"0.01":undefined} className="min-h-10 w-full rounded-[7px] border border-plum/15 bg-white px-3 text-xs outline-none focus:border-magenta"/></label>}
function TextArea({label,name,defaultValue,placeholder,wide=false}:{label:string;name:string;defaultValue?:unknown;placeholder?:string;wide?:boolean}){return <label className={`block ${wide?"sm:col-span-2":""}`}><span className="mb-1.5 block text-[10px] font-bold">{label}</span><textarea name={name} defaultValue={String(defaultValue??"")} placeholder={placeholder} rows={4} className="w-full rounded-[7px] border border-plum/15 bg-white px-3 py-2 text-xs outline-none focus:border-magenta"/></label>}
function Status({value}:{value:string}){const color=/confirmed|paid|active|completed/i.test(value)?"bg-green-100 text-green-800":/cancel|declin|ended/i.test(value)?"bg-red-100 text-red-700":/request|pending|scheduled/i.test(value)?"bg-amber/20 text-[#9b5a00]":"bg-blue-100 text-blue-700";return <span className={`inline-flex rounded-full px-2.5 py-1 text-[9px] font-semibold ${color}`}>{value}</span>}
function Stars({value}:{value:number}){return <span className="mt-1 block text-xs text-amber">{Array.from({length:5},(_,i)=><span key={i}>{i<Math.round(value)?"★":"☆"}</span>)}</span>}
function Empty({text}:{text:string}){return <div className="mt-4 rounded-[9px] border border-dashed border-plum/20 bg-blush/20 p-5 text-center text-xs text-ink/60">{text}</div>}
function dateText(value:unknown){if(!value)return "—";const d=new Date(String(value));return Number.isNaN(d.getTime())?String(value):d.toLocaleString([],{month:"short",day:"numeric",hour:"numeric",minute:"2-digit"})}
function styleName(c:Ctx,id:unknown){return String(c.styles.find(s=>s.id===id)?.name||"Braiding Service")}
function stylistName(c:Ctx,id:unknown){return String(c.stylists.find(s=>s.id===id)?.name||"Any stylist")}
function optionText(value:unknown){if(!Array.isArray(value))return "";return value.map((o)=>{const x=o as Record<string,unknown>;return `${x.label||x.name||"Option"}|${x.price_add||x.price||0}`}).join("\n")}
